INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1423, 190944, 2, 1053, '客家流沙之老珠子', '泥洋村村子象插秧时无意掉在山林间的一撮苗，便蓬勃了起来。山路虽弯，山却挺拔；毗邻江西省，所以村人一不小心在山腰打个“溜溜趟”便摔到江西去了。按理说是个有风水的地方，院墟乡最早一名大学生老珠子就是这个村子出生的。县乡政府的领导干部中，泥洋派从来是独霸一方，外地来的领导干部上任前谁都得先拜过这只庙。但绝少有出类拨萃者能升迁至地区一二把手以上的职位，即使有，也是昙花一现的谢落。比如当上平坝市长的谢民政，就任二个月后回家，因为一时高兴想亲自驾驶，和司机对调了座位，刚起动，便有一块利石自一里外的石场飞来击碎了脑壳；又如组织部的黄选，经过一番关系拼搏后，眼见调令已至，上任在即，却被假红菇药翻，抢救后虽未丧命，却落了个面瘫，全盘尽失。还有几位，都是不同时期出现的优秀人物，却都在他们意气风发正待大展拳脚之时发生剧变，陡然直下。以至于后来泥洋派的领导即便有再好的机会，却也宁愿窝在山城作土上皇，某某已官至县长、县委shu记，便会笑称自已是封顶了，并坚决拒绝更好的升迁机会。 
<br>
<br>           泥洋村的人的神是灶头香火熏黑的毛泽东和朱德的画像，据说他们早期在这块贫瘠的山林中东躲西藏；茂荣家还借过一口破锅给红军乔装补锅汉躲避白狗子们。泥洋村人最恨的是谁，他们会给你一个绝对意料不到的答案――明太祖朱元璋。在老人的指引下你可以爬上海拨最高的三角庙顶峰，朝西观望，这绵延的山脉中居然有奇异景象，神玳山的半腰隆起一块，俨然是一只下山之龟，要饮那中山河水！龟蛇皆为龙的象征，明太祖一统天下后，怕再有人起兵谋反，便派识星象风水的太监全国查看，先治龙脉以绝后患，这神玳山上的龟便受其涂毒，gui头上覆了巨石，是一座扁平的小石山，从此断了龙脉，世代不再出圣人，却出了不少怪才。泥洋村蜗居在龟脚下象是颗风干了的鸟粪，曾有外出学子回村后提议炸平了那石山，老人们却只是摇头，揶揄的望着年青气旺的后辈们微笑。 
<br>
<br>           老珠子再度回到泥洋时，已经不再有鞭炮和笑脸迎接他了，他只身从平坝市走回泥洋，鞋烂了，衣服也脏乱，裤腿一长一短的沾满了黄泥巴，最刺眼的还是他刚起色一点的头发，悲哀的证明了剃光的历史。只有老妈点燃了一把草在门口让他跨过驱邪，当他低下头迈进家门的一瞬间，一阵潮涌的晕眩让他差点摔倒在地上。 
<br>
<br>           离家六年了，重新拾起农活来，锄头竟然屎桶般沉。更让老珠子受不了的是村人的眼光――当初他是戴着大红花，光荣佬的大型拖拉机专程送他到平坝坐长途车，泥洋到八里坪十二里的路上弥漫着炮竹的硝香，一路碎红象是手持鸟铳的明山等猎手的脸，泥洋村人十里相送，连狗们也成群的跟在人群后……现在，或许是他们要拾回曾经为他而骄傲赞扬那种平衡了。人们不会耻笑整天游手好闲的半大佬，不会看不起老婆曾与人通奸的有肾炎的米谷佬，也对终年半担谷换条新裤子的石英古习以为常，但对老珠子的这种大起后的大落却引以为耻。而且老珠子是被学校开除退回原籍的，他所犯案件的定性――流氓罪！ 
<br>
<br>          其实以现在的眼光看来，老珠子的流氓行为实在算不了什么。一个从未出过山门的山里娃，在大学里疯狂的喜欢上了一名女生。老珠子因打报告申请到厨房烧锅炉，赚得两套伙头的黑棉袄，赢得了“烤黑薯”的称号，即便他使尽了浑身解数，那女孩都只是躲着他，但在背地里却暗暗鄙薄他的土。某一天，老珠子在图书馆遇上她，她坐在长板凳上聚精会神的看书，一点也没察觉老珠子已陶醉在她清淡的雪花膏香味中――那是他一生中闻过的最好的味道。他细细的打量她身体的一切细节，褡袢的白凉鞋，圆润均称的小腿，白皙娇嫩的脖颈……不知不觉的，他的身体象是吸入了乙醇，焕发着从未有过的亢奋，有一股躁热的气流在他周身流窜。她那薄薄的连衣裙勾勒出了发育姣好的身段，他梦游似的站在她身后，也站在所有人的瞳孔里。就在她起身时，他突然发现她的胸部有明显的乳头顶起的浮凸轮廓，身上那股气流已将他所有的理智撕成碎片，在众目睽睽之下，他就那么直通通的一把抓住她的乳fan！直到清脆的一声耳光，众人哗然而上把他揿在地上，他才明白自已做了什么傻事…… 
<br>
<br>           泥洋人形容不会干农活的人宽容的叫先生，但老珠子不属于宽容的范畴，他只能被奚落和嘲讽。农活做不来，犁田倒是将铁犁拗断了几把。耙田时更是糟糕，民选有心要看老珠子出丑，竟破天荒把大牛古借给他使用。牛古没吃饱，又欺生，老珠子第一声吆喝时，那牛古竟诧异的回头望了他一眼，复转头，屹然不动，反刍胃草，老珠子运足了气大喊一声“驾”！牛古优雅的一甩尾巴，将他甩了一脸水，引来不少蹲在田头观赏的闲人的哄笑，民选大笑说先生你没牙黄呵牛都不听你使唤哩！好歹走了步，却总是慢慢吞吞，拐弯时干脆赖着狠啃几口隔田坎上乌嬷的豆子苗。乌嬷闻讯赶来，在旁边虎着脸盯老珠子，再一次拐弯时，牛古竟不管老珠子声嘶力竭的吆喝，也不顾牛鼻圈简直要把鼻子分裂，专心致志的啃豆子苗……老珠子气急败坏之下狠狠一竹鞭，误中牛古臀下�G丸，牛古猛然一惊，竟跃坎跳下，老珠子卒不及防，手中的铁扶耙也脱手拖去，破空滑落时狠狠的扎在牛古臀上，牛身上马上出现了七八个血泉眼，剧痛之下更是落荒狂奔，那铁耙便被拖曳、磕碰、翻腾着在牛身上制造出更多血洞。下坝一马平川的田原，在牛蹄的狂乱下泥浪飞花，鲜红的牛血象数条散乱的长彩带，漂在水田新鲜的混浊中泅散。最后，牛古血尽力衰，被两根朽烂的篱笆一绊，即轰然倒地……一头壮年大牛古变成屠宰场里不值钱的肉，民选已脸色铁青的窥视老珠子的一间老房地基，若不是远房江西表叔出面，老珠子还真的作了人力拉犁的准备。 
<br>
<br>           在表叔的帮助下，老珠子开始往江西偷偷跑生意，不过所谓的生意，无非是贩卖些蔬菜、兔狗等，披星戴月往返于两省间，赚点物价差，终究脸生，又是带些书生气的嫩手，时常会被小贩们耍弄。他还随表叔跑过一次“赶牛岗”，从江西偏僻的农村费尽心机买来二十几头黄牛。比不得肉牛可以不管它们死活用车载，这些耕牛是土命，离不得土的，只能让它们慢慢的走。老珠子和表叔两人餐风露宿，每天要找到草甸子待牛群吃个半饱才能继续上路。一百多里的路，他们走了半个多月！老珠子跟在骚烘烘的牛群后走，性子被磨得简直要发疯。一路上表叔一直向老珠子兜售他可怜的人生观，一个老婆两亩地三餐温饱的低廉，到表叔最后说出要老珠子娶了他那残疾的女儿时，老珠子终于愤然“过河拆桥”，重新独自面对那些奸诈的小贩们。 
<br>
<br>           在一次从江西进年货时，由于货源紧缺，表叔不计前嫌，帮忙张罗了三十只活鸡，半路上又遇上一个拎鸡鸭的老表，老朱子看他似急需用钱，便把价钱压得极低，那老表居然也卖给了。原想今年市面上鸡鸭紧俏，奇货可居，家里先养上一阵子，等年关出售，好多赚一点还债，不料几天内全部发瘟病死掉，还使全村的鸡鸭在过年前一个月也被传染死光――那是泥洋村唯一一次没有鸡鸭过的年。债主们年关索债――尽管有的也就才那么十来元钱；乌嬷在大年三十还冲到家门口来跳大神似的骂。老珠子在众人的斥骂声中，脸色慢慢的失去了红润，胡子以惊人的速度疯长，斥骂声在他耳边整夜整夜的萦绕，房屋四周鸡鸭的烂臭味将他的所有情感催毁贻尽。整个正月，老娘几乎是在家门口跪着过完的，一名撑黑布伞的老师用手帕捂着鼻子，在门口凝视了五分钟，终于象救命稻草漂进了老珠子黑暗的空间。 
<br>
<br>           说来九一老师也算是老珠子拐了七个弯的表亲戚，他以前也曾想过让老珠子来小学代课，却因为老珠子的流氓罪实在让老师们忌讳而作罢，现在看到老珠子和老娘的年过得着实凄惨，动了隐恻之心，便向已经开始接受牛仔裤的老师们极力说服。总算从厨房伙头兼一年级语文课开始，三十元一个月工资，连工带教过了七年。在这七年中，老珠子沉默寡言，起初人们还会提起他以前意气风发的青春模样，到后来看他整天闷不吭声，小孩子捡了小石子丢他也只是傻笑一下，便直称老珠子为那个小学伙头了。他甚至承包了学校的屎缸卫生，每到周未便戴着口罩一担担粪便挑得一路臭气；有些年少气盛的师范生不满学校的分配，拿老珠子来出气，他低着头，不无认真的听从训导，一脸不知所衷的谄笑。九一老师偶尔也含蓄的提醒老珠子做人要有点脾气，有点自尊，但时间一长，也就懒得说了。某个冬天，调皮的四年级学生调唆了发颠的四姑婆说伙头骂她，她冲到小学厨房，持着撖面杖粗的木棒追打，身材不算矮小的老珠子惊恐的满学校跑，破袄棉絮满天飞扬……在好一段时期，伙头一词还成了泥洋村最流行的损人词语，它代biao着无能、怯懦、低贱、龌龊、下作……事实上，老珠子教的学生成绩虽没有名列前茅，但受他版书影响，字都写得漂亮、方正。有时人们提起泥洋小学学生的书法水平普遍不错，想到那个伙头，终究他是个上不得桌面的代课老师，对外宣传不得。即便学区有领导光临，问起是谁的功劳，老师们也是含糊其词，支吾过去。有一次学区校长下访泥洋小学。就餐时，学区校长问到这次勇夺书法比赛特等奖的作品倒底是谁的手笔，正好老珠子躬着身上鱼汤，老师们都含着泥汤匙望着本校九一校长，看他如何作答？老珠子竟然忘记了手中鱼汤的滚烫，学区校长听到老珠子的手指被烫得滋滋作响，不禁扭头莞尔一笑：难道是你么？佝偻着背的老珠子激动的一点头，竟然一弯鼻涕坠入鱼汤中。因此落下美名：“老珠子”。隔年，因下海风潮汹涌，院墟中学老师青黄不接，需一批代课老师，向小学借用，学区校长在开会时无意中回忆起鱼汤旧事，脸有笑意，被其他老师“揭发”，便供出了老珠子。这时老珠子已快四十岁了。 
<br>
<br>           在四十岁以前，邻近没有任何姑娘肯嫁给老珠子，也不知道他成年以来性问题是如何解决的？促狭的泥洋人编造出许多关于老珠子性方面的逸闻，有说他老是偷窥妇人喂奶;七十九的金秀奶奶在自家篱笆上丢了件侧面襟的秋衣，还几度踱到老珠子门口张望；老八古说每天晚上那个伙头名义上是为猪嬷加夜料，实际上从他穿着背心短裤就可以想象他真正是要干什么丑陋事――明山还信誓旦旦的说的确看过伙头的猪嬷下过一窝人头猪身的崽，连猪嬷自已都不认，全部被它吃回肚去了！也有的说那个伙头总是爱把人家的牛嬷往林子里赶……这倒冤枉他了，他顶多只瞟过它们的性器几眼，并作了些臆想。还有鸡鸭狗之类的，银真嬷她们女人捉起鸡嬷手指伸进去搜蛋是天经地义，但轮到那个伙头身上，手指便成了另一样龌龊的器官；有时这些非议倒是类似于一种提醒，但他毕竟还是艰难的熬过来了。 
<br>
<br>           院墟中学是老珠子新生的开始。中学很多年轻新老师，同批来代课的小学教师大部分也是不认识的，人们似乎已经淡忘了他的经历。校领导班子对代课老师们寄予极大的希望，要他们尽量发挥自已的才干。老珠子开始执教不同年段的学生，并当上了班主任。年底娶了一个女人，叫金玉良，大他三岁，因为不会生育而被前夫抛弃。老珠子无所谓孩子，而且玉良嬷喜欢用的也是百雀灵雪花膏――他一辈子都怀念那味道。他勤恳教学，学生成绩也不错，从同事们偶尔请他聚餐和学生们对他的尊敬中，他慢慢的找回了自已，恢复了脊背的挺直。在校外租了间民房，偶尔也接老娘下来尽尽孝。 
<br>
<br>           某年春夏之交，平坝学区发生一起影响恶劣的师生恋，因为老师竟和学生私奔海南去了。全学区严肃整顿校风校纪，院墟中学照例举行全校性大会，所有班主任带班坐在前排聆听训话，校长、副校长、教导主任、各级年段长逐一发言，在校长着重强调女生绝不可单独到男老师房间时，左眼皮发痒，抓挠了一下，刚好眼风就瞟了老珠子方向一会，台下学生扭头眼神紧跟，竟引起一片苍蝇般嗡嗡私语。老珠子脸色煞白，虽然心里明白校长也许并非故意，但此刻的难堪实在是扫荡尽了他多年以来苦心经营的脸面。而且关于他犯过流氓罪的事实象星火燎原在学校迅速蔓延，还传走了样。少数维护他的说只是别人对他的一种污蔑，其实他并没有耍过流氓，是被陷害的，那女生自已作骚勾引老珠子。更广泛的是演进成强奸罪――那可是最下作的事。因此，也不管事后校长委婉的表示歉意，心中蓄下了狠，趁校长向其询问校舍扩建规划时，暗暗将明细帐复制了一份，惊喜的发现校长不仅有将公家钢材拉回家盖房子的隐私，而且还掌握了他贪污二万余元的真凭实据。后年，老珠子侄儿竞争院墟中学校长一职，他轻描淡写便将侄儿的对手踢下马来。 
<br>              
<br>           有了当校长的侄儿，老珠子成了第一个非正式教师却任初三年段长的。他重新找回青春，不分昼夜的出没在属于他管辖的区域内，严抓狠干。代课老师们学习黄岗中学刻苦抓考题，居然有了前所未有的升学率。因此校长等一干人获得教育局按排出游香港的机会，只可惜老珠子无缘；侄儿因而感到更加的对他不起，回校后即着手为他调整了一套仅次于自已的住房。老珠子住在这宽敞明亮的套房，闻着身边的雪花膏香味，惬意的听《大宅门》中《挑滑车》的唱腔：看那前方黑（HE）洞――洞，分明是贼巢穴，待俺赶上杀他个片甲不留……他象以前大学教授的风度包装自已，不问寒暑头上都是一顶鸭舌帽，鼻梁架一副平光眼镜，扣紧的中山装，走路轻慢若有所思状……只是别人的笑总是会让他产生狐疑。特别是晚自习时，他一推门进入班级，那些小家伙立即噤若寒鸦，脸部表情从忘情大笑到一本正经的急剧收敛，他感觉他们是在讨较他的过去。他曾经施了些小恩惠给某些爱讨好老师的班干部，循循善诱的问学生们对他的看法，但他们给予的回答都让他不尽满意。某一次，有学生在班级胡闹，在门上架了支扫帚，原想捉弄别人的，不料老珠子忽然出现，全班学生看着那把该死的扫帚砸在老珠子头上仍能保持一本正经，但打落老珠子的平光眼镜单边悬在耳朵上的滑稽却让他们无法再忍，稚嫩的野笑将老珠子的火气团成一颗雷。但无人敢承认，老珠子不解气的训了几句话，便悻悻的摔门出来，不料门刚反弹回去，他便听到教室里有人哗众取宠的唱《铁窗泪》，他的耳朵精确的判断了声源方位，把那小同学叫到办公室，和蔼的叫近了，猛然一个老巴掌扫过去，那位小家伙捂着火辣辣的脸，不敢相信的看着仍带笑意的老珠子，半晌才哭出声来，在他咿呀的哭喊中，老珠子多年来的压抑居然象被打开洪水闸门，汹涌渲泻，畅快不已。玉良嬷来月经的时候，他总是爱到教学楼逛上几圈，不断的借助学生娇嫩的脸皮开启压抑闸门。虽然有时学生会向家长告状，但那些农村老汉总是固执的维持原判，即便再娇纵孩子的，闹到校长那儿就平息了。次数多了，校长示意老珠子不要太过火，但老珠子却情难自禁，一有机会，照样对看不顺眼的学生拳脚并施。不知哪一天起，原本唯唯诺诺的老珠子已成了学生闻名色变的狠手。 
<br>
<br>           五十六岁一过，玉良嬷绝经了，身子蔫蔫的，在性事方面便变得更加冷淡。老珠子开始不耐烦她赖在身边，便总是找借口打发她回娘家去住。幸好玉良嬷更乐于呆在娘家，还养了一头终日呆在她怀里的阉猫。不久，因为接连有老师将学生打出脑震荡、学生被全班辱打投河自尽的事，教育局几度被告上法庭，便再三明令严禁体罚，老珠子便换了花样对待调皮的学生，叫学生裸着上身滚杉枝，命令女学生撑在厕所板上闻气味……有一回校长去初三某班查看，居然发现有一半以上的学生逃课，推门进去正待怒喝班长点名时，发现那些“逃课”的学生竟然全都蜷缩在三十公分高的木桌底下，心里明白肯定是那屡劝不听的老珠子的作为。再有一次，老珠子罚一名调皮的学生光着膝盖在高高的讲台桌上跪沙，谁料那学生不小心摔下来伤了腿，正好他的舅舅有在教育局工作的朋友，便闹得翻江倒海，教育局领导严厉批评院墟中学，要求清理教师队伍中的败类……侄儿对老珠子的恃功放狂也已经有些受不了了，而且老珠子好象变得越来越糊涂，在政治课上吹嘘自已是院墟第一名大学生，说自已的大学同学现在都是省厅级干部；在教务会议上更是有些不知轻重，有时竟打断了自已的话，武断的作决定什么该怎么样……这还算不了什么，最要命的是有人发现已经有女生频繁出没他房间了。校长寻思如何处理这曾有恩于他的叔叔，必须在出事之前把他打发回泥洋老家。便找了个理由，不再让老珠子任年段长了。某日看到初三（五）班的大胸脯女生溜进对门老珠子房间，关闭了门十三分钟未出，就让贴心的教导主任率领两名血气方刚的体育老师突然破门而入，老珠子和那女生抱成一团，正熊在沙发上看电视，他的手还来不及从女孩的胸衣里撤出，女孩子吓得哇的大哭起来，说她成绩差是老珠子说有教育局的朋友能帮她弄到一个好的中专学校去……老珠子面如死灰，已经开始干瘪的两颊嚅嗫了两下，终于说不出话来。校长及时赶到，并怒斥几名多事的老师，但教导主任愤怒的一撸值勤袖套，甩在茶几上以辞职相胁，针锋相对，若不是两名体育老师死命拉住，校长手里的手电是要劈过去的。经过一番商榷后，最终这件事没有泄漏出去，老珠子也保住了脸面，只是委屈要在门卫的岗位呆些岁月了。 
<br>
<br>           过了两年，玉良嬷查出子宫癌晚期，老珠子腆着老脸四处借钱，直到山穷水尽，那雪花膏的淡淡清香终于还是散去。祸不单行，侄儿在新一轮的校长竞聘时，人际关系中败阵下来，调离了院墟中学，降为普通教师，不再有领导权力。院墟中学新来的校长扫了一眼目光日渐呆滞的老珠子，第二天就让他卷起铺盖走人…… 
<br>
<br>           离泥洋最近的墟是八里坪墟，每当墟天，整个市场闹哄哄时，便有一名穿着脏破黑棉袄的老头笼着袖，蹲在木桥头卖兔子。某日，有 “福佬鬼”无奈的操着普通话询问老头的兔子价钱，老头以标准的天津腔回答，令对方大惊失色。旁边熟悉的人唏的一笑，说别小看了山里人他可是天津名牌大学的呢，惊异中再要问，人家便一呶嘴，朝着神玳山的方向说知道泥洋有只神龟么？“福佬鬼”自然好奇的转身遥望，看那山峦起伏，竹海绵延，密林掩盖了所有的泥土呼吸，已忘了屁股向着老头晃动的不敬。老头漠然的视线从“福佬鬼”裆下穿过，看那或宽或窄的世界悄悄离他而去。', '泥洋村村子象插秧时无意掉在山林间的一撮苗，便蓬勃了起来。山路虽弯，山却挺拔；毗邻江西省，所以村人一不小心在山腰打个“溜溜趟”便摔到江西去了。按理说是个有风水的地方，院墟乡最早一名大学生老珠子就是这个村子出生的。县乡政府的领导干部中，泥洋派从来是独霸一方，外地来的领导干部上任前谁都得先拜过这只庙。但绝少有出类拨萃者能升迁至地区一二把手以上的职位，即使有，也是昙花一现的谢落。比如当上平坝市长的谢民政，就任二个月后回家，因为一时高兴想亲自驾驶，和司机对调了座位，刚起动，便有一块利石自一里外的石场飞来击碎了脑壳；又如组织部的黄选，经过一番关系拼搏后，眼见调令已至，上任在即，却被假红菇药翻，抢救后虽未丧命，却落了个面瘫，全盘尽失。还有几位，都是不同时期出现的优秀人物，却都在他们意气风发正待大展拳脚之时发生剧变，陡然直下。以至于后来泥洋派的领导即便有再好的机会，却也宁愿窝在山城作土上皇，某某已官至县长、县委shu记，便会笑称自已是封顶了，并坚决拒绝更好的升迁机会。

泥洋村的人的神是灶头香火熏黑的毛泽东和朱德的画像，据说他们早期在这块贫瘠的山林中东躲西藏；茂荣家还借过一口破锅给红军乔装补锅汉躲避白狗子们。泥洋村人最恨的是谁，他们会给你一个绝对意料不到的答案――明太祖朱元璋。在老人的指引下你可以爬上海拨最高的三角庙顶峰，朝西观望，这绵延的山脉中居然有奇异景象，神玳山的半腰隆起一块，俨然是一只下山之龟，要饮那中山河水！龟蛇皆为龙的象征，明太祖一统天下后，怕再有人起兵谋反，便派识星象风水的太监全国查看，先治龙脉以绝后患，这神玳山上的龟便受其涂毒，gui头上覆了巨石，是一座扁平的小石山，从此断了龙脉，世代不再出圣人，却出了不少怪才。泥洋村蜗居在龟脚下象是颗风干了的鸟粪，曾有外出学子回村后提议炸平了那石山，老人们却只是摇头，揶揄的望着年青气旺的后辈们微笑。

老珠子再度回到泥洋时，已经不再有鞭炮和笑脸迎接他了，他只身从平坝市走回泥洋，鞋烂了，衣服也脏乱，裤腿一长一短的沾满了黄泥巴，最刺眼的还是他刚起色一点的头发，悲哀的证明了剃光的历史。只有老妈点燃了一把草在门口让他跨过驱邪，当他低下头迈进家门的一瞬间，一阵潮涌的晕眩让他差点摔倒在地上。

离家六年了，重新拾起农活来，锄头竟然屎桶般沉。更让老珠子受不了的是村人的眼光――当初他是戴着大红花，光荣佬的大型拖拉机专程送他到平坝坐长途车，泥洋到八里坪十二里的路上弥漫着炮竹的硝香，一路碎红象是手持鸟铳的明山等猎手的脸，泥洋村人十里相送，连狗们也成群的跟在人群后……现在，或许是他们要拾回曾经为他而骄傲赞扬那种平衡了。人们不会耻笑整天游手好闲的半大佬，不会看不起老婆曾与人通奸的有肾炎的米谷佬，也对终年半担谷换条新裤子的石英古习以为常，但对老珠子的这种大起后的大落却引以为耻。而且老珠子是被学校开除退回原籍的，他所犯案件的定性――流氓罪！

其实以现在的眼光看来，老珠子的流氓行为实在算不了什么。一个从未出过山门的山里娃，在大学里疯狂的喜欢上了一名女生。老珠子因打报告申请到厨房烧锅炉，赚得两套伙头的黑棉袄，赢得了“烤黑薯”的称号，即便他使尽了浑身解数，那女孩都只是躲着他，但在背地里却暗暗鄙薄他的土。某一天，老珠子在图书馆遇上她，她坐在长板凳上聚精会神的看书，一点也没察觉老珠子已陶醉在她清淡的雪花膏香味中――那是他一生中闻过的最好的味道。他细细的打量她身体的一切细节，褡袢的白凉鞋，圆润均称的小腿，白皙娇嫩的脖颈……不知不觉的，他的身体象是吸入了乙醇，焕发着从未有过的亢奋，有一股躁热的气流在他周身流窜。她那薄薄的连衣裙勾勒出了发育姣好的身段，他梦游似的站在她身后，也站在所有人的瞳孔里。就在她起身时，他突然发现她的胸部有明显的乳头顶起的浮凸轮廓，身上那股气流已将他所有的理智撕成碎片，在众目睽睽之下，他就那么直通通的一把抓住她的乳fan！直到清脆的一声耳光，众人哗然而上把他揿在地上，他才明白自已做了什么傻事……

泥洋人形容不会干农活的人宽容的叫先生，但老珠子不属于宽容的范畴，他只能被奚落和嘲讽。农活做不来，犁田倒是将铁犁拗断了几把。耙田时更是糟糕，民选有心要看老珠子出丑，竟破天荒把大牛古借给他使用。牛古没吃饱，又欺生，老珠子第一声吆喝时，那牛古竟诧异的回头望了他一眼，复转头，屹然不动，反刍胃草，老珠子运足了气大喊一声“驾”！牛古优雅的一甩尾巴，将他甩了一脸水，引来不少蹲在田头观赏的闲人的哄笑，民选大笑说先生你没牙黄呵牛都不听你使唤哩！好歹走了步，却总是慢慢吞吞，拐弯时干脆赖着狠啃几口隔田坎上乌嬷的豆子苗。乌嬷闻讯赶来，在旁边虎着脸盯老珠子，再一次拐弯时，牛古竟不管老珠子声嘶力竭的吆喝，也不顾牛鼻圈简直要把鼻子分裂，专心致志的啃豆子苗……老珠子气急败坏之下狠狠一竹鞭，误中牛古臀下�G丸，牛古猛然一惊，竟跃坎跳下，老珠子卒不及防，手中的铁扶耙也脱手拖去，破空滑落时狠狠的扎在牛古臀上，牛身上马上出现了七八个血泉眼，剧痛之下更是落荒狂奔，那铁耙便被拖曳、磕碰、翻腾着在牛身上制造出更多血洞。下坝一马平川的田原，在牛蹄的狂乱下泥浪飞花，鲜红的牛血象数条散乱的长彩带，漂在水田新鲜的混浊中泅散。最后，牛古血尽力衰，被两根朽烂的篱笆一绊，即轰然倒地……一头壮年大牛古变成屠宰场里不值钱的肉，民选已脸色铁青的窥视老珠子的一间老房地基，若不是远房江西表叔出面，老珠子还真的作了人力拉犁的准备。

在表叔的帮助下，老珠子开始往江西偷偷跑生意，不过所谓的生意，无非是贩卖些蔬菜、兔狗等，披星戴月往返于两省间，赚点物价差，终究脸生，又是带些书生气的嫩手，时常会被小贩们耍弄。他还随表叔跑过一次“赶牛岗”，从江西偏僻的农村费尽心机买来二十几头黄牛。比不得肉牛可以不管它们死活用车载，这些耕牛是土命，离不得土的，只能让它们慢慢的走。老珠子和表叔两人餐风露宿，每天要找到草甸子待牛群吃个半饱才能继续上路。一百多里的路，他们走了半个多月！老珠子跟在骚烘烘的牛群后走，性子被磨得简直要发疯。一路上表叔一直向老珠子兜售他可怜的人生观，一个老婆两亩地三餐温饱的低廉，到表叔最后说出要老珠子娶了他那残疾的女儿时，老珠子终于愤然“过河拆桥”，重新独自面对那些奸诈的小贩们。

在一次从江西进年货时，由于货源紧缺，表叔不计前嫌，帮忙张罗了三十只活鸡，半路上又遇上一个拎鸡鸭的老表，老朱子看他似急需用钱，便把价钱压得极低，那老表居然也卖给了。原想今年市面上鸡鸭紧俏，奇货可居，家里先养上一阵子，等年关出售，好多赚一点还债，不料几天内全部发瘟病死掉，还使全村的鸡鸭在过年前一个月也被传染死光――那是泥洋村唯一一次没有鸡鸭过的年。债主们年关索债――尽管有的也就才那么十来元钱；乌嬷在大年三十还冲到家门口来跳大神似的骂。老珠子在众人的斥骂声中，脸色慢慢的失去了红润，胡子以惊人的速度疯长，斥骂声在他耳边整夜整夜的萦绕，房屋四周鸡鸭的烂臭味将他的所有情感催毁贻尽。整个正月，老娘几乎是在家门口跪着过完的，一名撑黑布伞的老师用手帕捂着鼻子，在门口凝视了五分钟，终于象救命稻草漂进了老珠子黑暗的空间。

说来九一老师也算是老珠子拐了七个弯的表亲戚，他以前也曾想过让老珠子来小学代课，却因为老珠子的流氓罪实在让老师们忌讳而作罢，现在看到老珠子和老娘的年过得着实凄惨，动了隐恻之心，便向已经开始接受牛仔裤的老师们极力说服。总算从厨房伙头兼一年级语文课开始，三十元一个月工资，连工带教过了七年。在这七年中，老珠子沉默寡言，起初人们还会提起他以前意气风发的青春模样，到后来看他整天闷不吭声，小孩子捡了小石子丢他也只是傻笑一下，便直称老珠子为那个小学伙头了。他甚至承包了学校的屎缸卫生，每到周未便戴着口罩一担担粪便挑得一路臭气；有些年少气盛的师范生不满学校的分配，拿老珠子来出气，他低着头，不无认真的听从训导，一脸不知所衷的谄笑。九一老师偶尔也含蓄的提醒老珠子做人要有点脾气，有点自尊，但时间一长，也就懒得说了。某个冬天，调皮的四年级学生调唆了发颠的四姑婆说伙头骂她，她冲到小学厨房，持着撖面杖粗的木棒追打，身材不算矮小的老珠子惊恐的满学校跑，破袄棉絮满天飞扬……在好一段时期，伙头一词还成了泥洋村最流行的损人词语，它代biao着无能、怯懦、低贱、龌龊、下作……事实上，老珠子教的学生成绩虽没有名列前茅，但受他版书影响，字都写得漂亮、方正。有时人们提起泥洋小学学生的书法水平普遍不错，想到那个伙头，终究他是个上不得桌面的代课老师，对外宣传不得。即便学区有领导光临，问起是谁的功劳，老师们也是含糊其词，支吾过去。有一次学区校长下访泥洋小学。就餐时，学区校长问到这次勇夺书法比赛特等奖的作品倒底是谁的手笔，正好老珠子躬着身上鱼汤，老师们都含着泥汤匙望着本校九一校长，看他如何作答？老珠子竟然忘记了手中鱼汤的滚烫，学区校长听到老珠子的手指被烫得滋滋作响，不禁扭头莞尔一笑：难道是你么？佝偻着背的老珠子激动的一点头，竟然一弯鼻涕坠入鱼汤中。因此落下美名：“老珠子”。隔年，因下海风潮汹涌，院墟中学老师青黄不接，需一批代课老师，向小学借用，学区校长在开会时无意中回忆起鱼汤旧事，脸有笑意，被其他老师“揭发”，便供出了老珠子。这时老珠子已快四十岁了。

在四十岁以前，邻近没有任何姑娘肯嫁给老珠子，也不知道他成年以来性问题是如何解决的？促狭的泥洋人编造出许多关于老珠子性方面的逸闻，有说他老是偷窥妇人喂奶;七十九的金秀奶奶在自家篱笆上丢了件侧面襟的秋衣，还几度踱到老珠子门口张望；老八古说每天晚上那个伙头名义上是为猪嬷加夜料，实际上从他穿着背心短裤就可以想象他真正是要干什么丑陋事――明山还信誓旦旦的说的确看过伙头的猪嬷下过一窝人头猪身的崽，连猪嬷自已都不认，全部被它吃回肚去了！也有的说那个伙头总是爱把人家的牛嬷往林子里赶……这倒冤枉他了，他顶多只瞟过它们的性器几眼，并作了些臆想。还有鸡鸭狗之类的，银真嬷她们女人捉起鸡嬷手指伸进去搜蛋是天经地义，但轮到那个伙头身上，手指便成了另一样龌龊的器官；有时这些非议倒是类似于一种提醒，但他毕竟还是艰难的熬过来了。

院墟中学是老珠子新生的开始。中学很多年轻新老师，同批来代课的小学教师大部分也是不认识的，人们似乎已经淡忘了他的经历。校领导班子对代课老师们寄予极大的希望，要他们尽量发挥自已的才干。老珠子开始执教不同年段的学生，并当上了班主任。年底娶了一个女人，叫金玉良，大他三岁，因为不会生育而被前夫抛弃。老珠子无所谓孩子，而且玉良嬷喜欢用的也是百雀灵雪花膏――他一辈子都怀念那味道。他勤恳教学，学生成绩也不错，从同事们偶尔请他聚餐和学生们对他的尊敬中，他慢慢的找回了自已，恢复了脊背的挺直。在校外租了间民房，偶尔也接老娘下来尽尽孝。

某年春夏之交，平坝学区发生一起影响恶劣的师生恋，因为老师竟和学生私奔海南去了。全学区严肃整顿校风校纪，院墟中学照例举行全校性大会，所有班主任带班坐在前排聆听训话，校长、副校长、教导主任、各级年段长逐一发言，在校长着重强调女生绝不可单独到男老师房间时，左眼皮发痒，抓挠了一下，刚好眼风就瞟了老珠子方向一会，台下学生扭头眼神紧跟，竟引起一片苍蝇般嗡嗡私语。老珠子脸色煞白，虽然心里明白校长也许并非故意，但此刻的难堪实在是扫荡尽了他多年以来苦心经营的脸面。而且关于他犯过流氓罪的事实象星火燎原在学校迅速蔓延，还传走了样。少数维护他的说只是别人对他的一种污蔑，其实他并没有耍过流氓，是被陷害的，那女生自已作骚勾引老珠子。更广泛的是演进成强奸罪――那可是最下作的事。因此，也不管事后校长委婉的表示歉意，心中蓄下了狠，趁校长向其询问校舍扩建规划时，暗暗将明细帐复制了一份，惊喜的发现校长不仅有将公家钢材拉回家盖房子的隐私，而且还掌握了他贪污二万余元的真凭实据。后年，老珠子侄儿竞争院墟中学校长一职，他轻描淡写便将侄儿的对手踢下马来。

有了当校长的侄儿，老珠子成了第一个非正式教师却任初三年段长的。他重新找回青春，不分昼夜的出没在属于他管辖的区域内，严抓狠干。代课老师们学习黄岗中学刻苦抓考题，居然有了前所未有的升学率。因此校长等一干人获得教育局按排出游香港的机会，只可惜老珠子无缘；侄儿因而感到更加的对他不起，回校后即着手为他调整了一套仅次于自已的住房。老珠子住在这宽敞明亮的套房，闻着身边的雪花膏香味，惬意的听《大宅门》中《挑滑车》的唱腔：看那前方黑（HE）洞――洞，分明是贼巢穴，待俺赶上杀他个片甲不留……他象以前大学教授的风度包装自已，不问寒暑头上都是一顶鸭舌帽，鼻梁架一副平光眼镜，扣紧的中山装，走路轻慢若有所思状……只是别人的笑总是会让他产生狐疑。特别是晚自习时，他一推门进入班级，那些小家伙立即噤若寒鸦，脸部表情从忘情大笑到一本正经的急剧收敛，他感觉他们是在讨较他的过去。他曾经施了些小恩惠给某些爱讨好老师的班干部，循循善诱的问学生们对他的看法，但他们给予的回答都让他不尽满意。某一次，有学生在班级胡闹，在门上架了支扫帚，原想捉弄别人的，不料老珠子忽然出现，全班学生看着那把该死的扫帚砸在老珠子头上仍能保持一本正经，但打落老珠子的平光眼镜单边悬在耳朵上的滑稽却让他们无法再忍，稚嫩的野笑将老珠子的火气团成一颗雷。但无人敢承认，老珠子不解气的训了几句话，便悻悻的摔门出来，不料门刚反弹回去，他便听到教室里有人哗众取宠的唱《铁窗泪》，他的耳朵精确的判断了声源方位，把那小同学叫到办公室，和蔼的叫近了，猛然一个老巴掌扫过去，那位小家伙捂着火辣辣的脸，不敢相信的看着仍带笑意的老珠子，半晌才哭出声来，在他咿呀的哭喊中，老珠子多年来的压抑居然象被打开洪水闸门，汹涌渲泻，畅快不已。玉良嬷来月经的时候，他总是爱到教学楼逛上几圈，不断的借助学生娇嫩的脸皮开启压抑闸门。虽然有时学生会向家长告状，但那些农村老汉总是固执的维持原判，即便再娇纵孩子的，闹到校长那儿就平息了。次数多了，校长示意老珠子不要太过火，但老珠子却情难自禁，一有机会，照样对看不顺眼的学生拳脚并施。不知哪一天起，原本唯唯诺诺的老珠子已成了学生闻名色变的狠手。

五十六岁一过，玉良嬷绝经了，身子蔫蔫的，在性事方面便变得更加冷淡。老珠子开始不耐烦她赖在身边，便总是找借口打发她回娘家去住。幸好玉良嬷更乐于呆在娘家，还养了一头终日呆在她怀里的阉猫。不久，因为接连有老师将学生打出脑震荡、学生被全班辱打投河自尽的事，教育局几度被告上法庭，便再三明令严禁体罚，老珠子便换了花样对待调皮的学生，叫学生裸着上身滚杉枝，命令女学生撑在厕所板上闻气味……有一回校长去初三某班查看，居然发现有一半以上的学生逃课，推门进去正待怒喝班长点名时，发现那些“逃课”的学生竟然全都蜷缩在三十公分高的木桌底下，心里明白肯定是那屡劝不听的老珠子的作为。再有一次，老珠子罚一名调皮的学生光着膝盖在高高的讲台桌上跪沙，谁料那学生不小心摔下来伤了腿，正好他的舅舅有在教育局工作的朋友，便闹得翻江倒海，教育局领导严厉批评院墟中学，要求清理教师队伍中的败类……侄儿对老珠子的恃功放狂也已经有些受不了了，而且老珠子好象变得越来越糊涂，在政治课上吹嘘自已是院墟第一名大学生，说自已的大学同学现在都是省厅级干部；在教务会议上更是有些不知轻重，有时竟打断了自已的话，武断的作决定什么该怎么样……这还算不了什么，最要命的是有人发现已经有女生频繁出没他房间了。校长寻思如何处理这曾有恩于他的叔叔，必须在出事之前把他打发回泥洋老家。便找了个理由，不再让老珠子任年段长了。某日看到初三（五）班的大胸脯女生溜进对门老珠子房间，关闭了门十三分钟未出，就让贴心的教导主任率领两名血气方刚的体育老师突然破门而入，老珠子和那女生抱成一团，正熊在沙发上看电视，他的手还来不及从女孩的胸衣里撤出，女孩子吓得哇的大哭起来，说她成绩差是老珠子说有教育局的朋友能帮她弄到一个好的中专学校去……老珠子面如死灰，已经开始干瘪的两颊嚅嗫了两下，终于说不出话来。校长及时赶到，并怒斥几名多事的老师，但教导主任愤怒的一撸值勤袖套，甩在茶几上以辞职相胁，针锋相对，若不是两名体育老师死命拉住，校长手里的手电是要劈过去的。经过一番商榷后，最终这件事没有泄漏出去，老珠子也保住了脸面，只是委屈要在门卫的岗位呆些岁月了。

过了两年，玉良嬷查出子宫癌晚期，老珠子腆着老脸四处借钱，直到山穷水尽，那雪花膏的淡淡清香终于还是散去。祸不单行，侄儿在新一轮的校长竞聘时，人际关系中败阵下来，调离了院墟中学，降为普通教师，不再有领导权力。院墟中学新来的校长扫了一眼目光日渐呆滞的老珠子，第二天就让他卷起铺盖走人……

离泥洋最近的墟是八里坪墟，每当墟天，整个市场闹哄哄时，便有一名穿着脏破黑棉袄的老头笼着袖，蹲在木桥头卖兔子。某日，有 “福佬鬼”无奈的操着普通话询问老头的兔子价钱，老头以标准的天津腔回答，令对方大惊失色。旁边熟悉的人唏的一笑，说别小看了山里人他可是天津名牌大学的呢，惊异中再要问，人家便一呶嘴，朝着神玳山的方向说知道泥洋有只神龟么？“福佬鬼”自然好奇的转身遥望，看那山峦起伏，竹海绵延，密林掩盖了所有的泥土呼吸，已忘了屁股向着老头晃动的不敬。老头漠然的视线从“福佬鬼”裆下穿过，看那或宽或窄的世界悄悄离他而去。', NULL, '2002-12-09 11:03:00', 11, '20030217224926_bbsid_190944_board_2_7470c98006.html', '20030217224926');
